class Solution:
    def getMinSwaps(self, num: str, k: int) -> int:
        n = len(num)
        num = list(num)
        def is_wonderful(num):
            return sorted(num) == num and num != list(num)

        def next_wonderful(num):
            for i in range(n - 1, -1, -1):
                if num[i] < num[i - 1]:
                    return num[:i - 1] + sorted(num[i - 1:], reverse=True)
            return num

        count = 0
        for _ in range(k):
            num = next_wonderful(num)
            count += sum(a != b for a, b in zip(num, num[1:]))
        return count
```

